module m_module (
    input [3:0] c,
    output reg invalid_output
);

    always @(*) begin
        case (c)
            4'b0000: invalid_output = 1;
            4'b0001: invalid_output = 0;
            4'b0010: invalid_output = 1;
            4'b0011: invalid_output = 0;
            4'b0100: invalid_output = 1;
            4'b0101: invalid_output = 0;
            4'b0110: invalid_output = 1;
            4'b0111: invalid_output = 0;
            4'b1000: invalid_output = 1;
            4'b1001: invalid_output = 0;
            4'b1010: invalid_output = 1;
            4'b1011: invalid_output = 0;
            4'b1100: invalid_output = 1;
            4'b1101: invalid_output = 0;
            4'b1110: invalid_output = 1;
            4'b1111: invalid_output = 0;
            default: invalid_output = 0; // Default case
        endcase
    end
endmodule
